int compareInts(const void *a, const void *b) {
    return (*(int*)a) - (*(int*)b);
}

int totalFruits(int* fruits, int n) {
    // Step 1: copy & sort to compress values
    int* temp = malloc(n * sizeof(int));
    memcpy(temp, fruits, n * sizeof(int));
    qsort(temp, n, sizeof(int), compareInts);

    // Remove duplicates
    int unique = 1;
    for (int i = 1; i < n; i++) {
        if (temp[i] != temp[unique - 1]) {
            temp[unique++] = temp[i];
        }
    }

    // Step 2: compress original fruit values
    for (int i = 0; i < n; i++) {
        // binary search
        int lo = 0, hi = unique - 1;
        while (lo <= hi) {
            int mid = (lo + hi) / 2;
            if (temp[mid] == fruits[i]) {
                fruits[i] = mid; // compressed value
                break;
            }
            if (temp[mid] < fruits[i]) lo = mid + 1;
            else hi = mid - 1;
        }
    }

    free(temp);

    // Step 3: now we can safely use a small count array
    int *count = calloc(unique, sizeof(int));

    int left = 0, maxFruits = 0, types = 0;

    for (int right = 0; right < n; right++) {
        if (count[fruits[right]] == 0) types++;
        count[fruits[right]]++;

        while (types > 2) {
            count[fruits[left]]--;
            if (count[fruits[left]] == 0) types--;
            left++;
        }

        int window = right - left + 1;
        if (window > maxFruits) maxFruits = window;
    }

    free(count);
    return maxFruits;
}

